async function refreshProviderConfig(){try{serverKeyConfig=await fetch('/api/config',{cache:'no-store'}).then(response=>response.json())}catch{serverKeyConfig={openai:false,anthropic:false,byokOnly:false}}}
function jigsawScreen(n){const trayRows=Math.ceil((n*n)/4);return{width:1000,height:Math.max(760,350+trayRows*82),board:{x:20,y:40,size:600},reference:{x:670,y:40,size:200},tray:{x:670,y:330,size:68,gap:12,cols:4}}}
function jigsawRemaining(){return state.pieces.filter(piece=>!Object.values(state.placed).some(placed=>+placed===piece))}
function pointInJigsawSlot(point){const screen=jigsawScreen(state.n),{board}=screen;if(point.x<board.x||point.y<board.y||point.x>=board.x+board.size||point.y>=board.y+board.size)return null;const cell=board.size/state.n,col=Math.floor((point.x-board.x)/cell),row=Math.floor((point.y-board.y)/cell);return row*state.n+col}
function jigsawTileAt(point){const screen=jigsawScreen(state.n),{tray}=screen,col=Math.floor((point.x-tray.x)/(tray.size+tray.gap)),row=Math.floor((point.y-tray.y)/(tray.size+tray.gap));if(col<0||col>=tray.cols||row<0)return null;const withinX=(point.x-tray.x)%(tray.size+tray.gap),withinY=(point.y-tray.y)%(tray.size+tray.gap);if(withinX>tray.size||withinY>tray.size)return null;return jigsawRemaining()[row*tray.cols+col]??null}
function jigsawPointForSlot(slot){const screen=jigsawScreen(state.n),cell=screen.board.size/state.n;return{x:screen.board.x+(slot%state.n+.5)*cell,y:screen.board.y+(Math.floor(slot/state.n)+.5)*cell}}
function jigsawPointForTile(tile){const screen=jigsawScreen(state.n),index=jigsawRemaining().indexOf(tile),{tray}=screen;return index<0?null:{x:tray.x+(index%tray.cols)*(tray.size+tray.gap)+tray.size/2,y:tray.y+Math.floor(index/tray.cols)*(tray.size+tray.gap)+tray.size/2}}
function toast(t){const e=$('#toast');e.textContent=t;e.classList.add('show');clearTimeout(e.t);e.t=setTimeout(()=>e.classList.remove('show'),2400)}
function setRunButtonRunning(running){const button=$('#run-button');if(!button)return;button.innerHTML=running?'Stop agent <b>×</b>':'Run agent <b>↗</b>';button.classList.toggle('stop-agent',running)}
function escapeHtml(value){return String(value??'').replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]))}
function traceDrawerVisible(){return $('#drawer').classList.contains('show')&&$('#drawer-kicker').textContent==='RUN HISTORY'}
function followTraceTail(){if(!traceDrawerVisible()||!traceAutoFollow)return;requestAnimationFrame(()=>{const drawer=$('#drawer');drawer.scrollTop=drawer.scrollHeight})}
function trackTraceScroll(){const drawer=$('#drawer');drawer.onscroll=()=>{if(!traceDrawerVisible())return;traceAutoFollow=drawer.scrollHeight-drawer.scrollTop-drawer.clientHeight<56}}
function log(label,text,kind='',meta={}){trace.push({label,text,kind,...meta});if($('#drawer').classList.contains('show')){renderDrawerContent();followTraceTail()}}
function normaliseMap(map){const width=Math.max(...map.map(row=>row.length));return map.map(row=>row.padEnd(width,'#'))}
function parseGrid(map){let player,goal;const goals=[],crates=[];const base=normaliseMap(map).map((r,y)=>[...r].map((c,x)=>{if('.+*'.includes(c)){goals.push([x,y]);goal=[x,y]}if('$*'.includes(c))crates.push([x,y]);if('@+'.includes(c))player=[x,y];return c==='#'?'#':' '}));if(!player)throw new Error('Puzzle map has no player start.');return{base,player,goal,goals,crates,steps:0,pushes:0,solved:false}}
function resetLiveRun(){clearInterval(liveRun.timer);liveRun={timer:null,startedAt:0,events:[]};$('#live-run-panel').hidden=true}
function elapsed(){let seconds=Math.max(0,Math.floor((Date.now()-liveRun.startedAt)/1000));return `${String(Math.floor(seconds/60)).padStart(2,'0')}:${String(seconds%60).padStart(2,'0')}`}
function renderLiveRun(){const panel=$('#live-run-panel');if(!liveRun.startedAt){panel.hidden=true;return}panel.hidden=false;$('#live-run-elapsed').textContent=elapsed();$('#live-run-title').textContent=liveRun.title||'Agent is working on the puzzle.';$('#live-run-detail').textContent=liveRun.detail||'Preparing the next safe step.';$('#live-run-cost').textContent=lastUsage?formatUsage(lastUsage):'cost pending';$('#live-run-events').innerHTML=liveRun.events.slice(-4).map((event,index)=>`<li class="${index===liveRun.events.slice(-4).length-1?'current':'done'}">${event}</li>`).join('')}
function beginLiveRun(title,detail){resetLiveRun();liveRun.startedAt=Date.now();liveRun.title=title;liveRun.detail=detail;liveRun.events=['Workspace opened'];liveRun.timer=setInterval(renderLiveRun,400);renderLiveRun()}
function updateLiveRun(title,detail,event){if(!liveRun.startedAt)return;liveRun.title=title;liveRun.detail=detail;if(event&&liveRun.events.at(-1)!==event)liveRun.events.push(event);renderLiveRun()}
function finishLiveRun(title,detail){if(!liveRun.startedAt)return;updateLiveRun(title,detail,'Run complete');clearInterval(liveRun.timer);liveRun.timer=null;setTimeout(()=>{$('#live-run-panel').hidden=true},7000)}
function friendlyAction(direction,index,total){return `Move ${String(index+1).padStart(2,'0')}/${String(total).padStart(2,'0')} · ${({up:'↑ Up',down:'↓ Down',left:'← Left',right:'→ Right'})[direction]||direction}`}
function briefTrace(text,limit=180){const clean=String(text||'').replace(/[#*_`]/g,'').replace(/\s+/g,' ').trim();return clean.length>limit?`${clean.slice(0,limit-1).trim()}…`:clean}
function traceTone(entry){const label=entry.label||'';if(label==='PLAN UPDATE'||label==='DECISION')return'plan';if(label.includes('BRANCH')||label.includes('EXPLORER')||label==='SPAWN')return'branch';if(label.includes('HELPER')||label==='WORKSPACE')return'helper';if(label.includes('ACTION')||label.includes('CURSOR')||label==='BATCH'||label==='EXECUTION')return'action';if(label==='RESULT'||label==='RUN COMPLETE')return'result';if(label.includes('OBSERVATION'))return'observe';return entry.kind==='report'?'report':'neutral'}
function traceTitle(entry){return({
  'RUN START':'Run connected','OBSERVATION':'Board observation','SCREEN OBSERVATION':'Screen observation','PLAN UPDATE':'Plan checkpoint','ACTION PLAN':'Action batch','ACTION CHECK':'Action check','CURSOR DRAG':'Cursor drag','CURSOR BLOCKED':'Cursor blocked','BRANCH START':'Explorer dispatched','BRANCH REPORT':'Explorer report','EXPLORER LIMIT':'Explorer limit','HELPER FILE':'Helper drafted','HELPER RUN':'Helper executed','HELPER SKIPPED':'Helper skipped','WORKSPACE':'Workspace update','RUN COMPLETE':'Puzzle solved','RESULT':'Result','RUN ERROR':'Run needs attention','REPLAN':'Next decision requested','SOLVER AID':'Solver aid'
})[entry.label]||entry.label||'Update'}
function traceField(label,value){return value?`<div class="trace-field"><b>${escapeHtml(label)}</b><span>${escapeHtml(value)}</span></div>`:''}
function traceCard(entry,step,compact=false){const tone=traceTone(entry),fields=[];if(entry.explorer)fields.push(traceField('Explorer',entry.explorer));if(entry.observation)fields.push(traceField('Observed',entry.observation));if(entry.plan)fields.push(traceField('Plan',entry.plan));if(entry.reason)fields.push(traceField('Reason',entry.reason));if(entry.expected&&!compact)fields.push(traceField('Expected',entry.expected));if(entry.objective)fields.push(traceField('Question',entry.objective));if(entry.report)fields.push(traceField('Finding',entry.report));if(entry.actions?.length)fields.push(traceField('Actions',entry.actions.join(' · ')));if(entry.file)fields.push(traceField('File',entry.file));if(entry.output)fields.push(traceField(entry.status==='complete'?'Output':'Result',entry.output));if(entry.failure)fields.push(traceField('Check',entry.failure));const fallback=fields.length?'':`<p class="trace-summary">${escapeHtml(briefTrace(entry.text,compact?150:420))}</p>`;return`<article class="trace-item trace-${tone}"><div class="trace-head"><span class="trace-step">${String(step).padStart(2,'0')}</span><div><p class="trace-label">${escapeHtml(entry.label||'UPDATE')}</p><h3>${escapeHtml(traceTitle(entry))}</h3></div></div>${fields.length?`<div class="trace-fields">${fields.join('')}</div>`:fallback}</article>`}
function formatUsage(usage){if(!usage)return '—';const c=usage.estimatedCostUsd;return Number.isFinite(c)?`~$${c<.1?c.toFixed(4):c.toFixed(2)}`:'tokens tracked'}
function setUsage(usage){if(!usage)return;lastUsage=usage;$('#run-cost').textContent=formatUsage(usage);renderLiveRun()}
function resetRunContext(){trace=[];lastUsage=null;workspaces=[{id:'main',name:'Main agent',status:'ready',parent:'Authoritative workspace'}];activeWorkspace='main';$('#agent-count').textContent='1';$('#active-workspace').textContent='Main agent';$('#run-cost').textContent='—'}
function updateSolutionButton(){const button=$('#solution-button');button.hidden=type!=='sokoban'||!state?.solved}
function init(){runGeneration++;stop(true);resetLiveRun();resetRunContext();selectedPiece=null;selectedTile=null;const l=level();if(type==='sokoban'||type==='maze')state=parseGrid(l.map);else if(isKlotski())state={pieces:structuredClone(l.pieces),cols:l.cols||6,rows:l.rows||6,exitRow:l.exitRow??2,steps:0,solved:false,cursor:null,control:l.control||'logic'};else if(isJigsaw())state={n:l.n,art:l.art,asset:l.asset||'/assets/cat.jpg',steps:0,solved:false,pieces:shuffle([...Array(l.n*l.n)].map((_,i)=>i)),placed:{},reference:true,history:[],cursor:null,control:l.control||'click'};$('#puzzle-kicker').textContent=l.kicker;$('#arena-name').textContent=`${current().label} · ${l.name}`;$('#mode-copy').textContent=isMousePuzzle()?'Virtual computer / mouse':isJigsaw()?'Visual matching / abstract placement':'Structured logic';$('#game-caption').textContent=type==='sokoban'?'Arrow keys move the keeper. Every crate must land on a target.':type==='maze'?'Arrow keys navigate to the green exit.':isKlotski()?(isMousePuzzle()?'Drag the coloured blocks. The blue block must leave through the right-side exit.':'Select a numbered long tile, then use arrows. Example: 2U. Every tile moves only along its long axis.'):(isMousePuzzle()?'Drag a visual tile from the tray to a board cell. The cursor path is part of the run.':'Select a tile, then a destination. The live agent matches visible fragments without using mouse coordinates.');$('#undo-piece-button').hidden=!isJigsaw();$('#step-count').textContent='00';$('#push-count').textContent='00';$('#metric-two').textContent=type==='maze'?'cells explored':isJigsaw()?'pieces placed':isKlotski()?(isMousePuzzle()?'drags':'slides'):'pushes';$('#run-status').textContent='READY';$('#command-value').textContent='—';updateSolutionButton();renderBoard();if(isJigsaw())void prepareJigsawArtwork();renderCards()}
function shuffle(a){return a.sort(()=>Math.random()-.5)}
