$('#agents-tab').onclick=()=>openDrawer('agents');$('#workspace-tab').onclick=()=>openDrawer('workspace');$('#api-tab').onclick=()=>openDrawer('api');$('#trace-button').onclick=()=>openDrawer('trace');$$('[data-open-palette]').forEach(b=>b.onclick=()=>openDrawer(b.dataset.openPalette));$$('[data-close]').forEach(b=>b.onclick=closeDrawer);$('#run-button').onclick=run;$('#reset-button').onclick=init;$('#solution-button').onclick=()=>openDrawer('solution');document.addEventListener('keydown',e=>{if(!dirs[e.key.replace('Arrow','').toLowerCase()])return;e.preventDefault();let d=e.key.replace('Arrow','').toLowerCase();if(isKlotski()){if(isMousePuzzle())toast('This puzzle uses drag control. Grab a coloured block with the pointer.');else moveK(d)}else move(d)});init();refreshProviderConfig();
