async function playLiveActions(actions,source='Agent',generation=runGeneration,finalBatch=true){
  isRunning=true; $('#run-status').textContent='RUNNING';
  for(let index=0;index<actions.length;index++){
    if(!isRunning||generation!==runGeneration)break;
    const action=actions[index];let message;
    if(type==='sokoban'||type==='maze'){move(action,true);message=friendlyAction(action,index,actions.length)}
    else if(isJigsaw()){selectedTile=action.tile;placeTile(action.slot);message=`Tile ${action.tile+1} → board cell ${action.slot+1}`}
    log('EXECUTING',message,'action');
    updateLiveRun(`${source} is applying the verified route.`,message,message);
    await new Promise(resolve=>setTimeout(resolve,280));
  }
  isRunning=false;
  if(generation===runGeneration&&!state.solved&&finalBatch){$('#run-status').textContent='ERROR';failLiveRun(`${source} stopped before the board was solved.`,`${actions.length} validated steps were applied; no success was claimed.`)}
}
