  const label=entry.label==='AGENT NOTE'?'AGENT NOTE':entry.label,kind=['BRANCH START','BRANCH REPORT','HELPER FILE','HELPER RUN','WORKSPACE'].includes(label)?'report':'';
  const meta={phase:entry.phase,explorer:entry.explorer,observation:entry.observation,plan:entry.plan,reason:entry.reason,expected:entry.expected,objective:entry.objective,report:entry.report,actions:entry.actions,file:entry.file,status:entry.status,output:entry.output,failure:entry.failure};
